const config = {
  "previewFeatures": [],
  "clientVersion": "7.9.0",
  "engineVersion": "e922089b7d7502aff4249d5da3420f6fa55fc6ad",
  "activeProvider": "mysql",
  "inlineSchema": "// Waslah Fashion — Prisma schema\n// Clean redesign of the legacy `waslah_ecom` PHP schema (64 tables).\n//\n// Conventions:\n//   - Models are PascalCase singular; fields camelCase, mapped to the\n//     snake_case column names the data-migration script reads from.\n//   - Money is Decimal(12,2) throughout (legacy mixed 10,2 / 12,2 / 14,2).\n//   - Enums are domain-prefixed because Prisma enum names are global.\n//   - Legacy redundancies deliberately dropped: `banners` (dead, superseded\n//     by `sliders`), `stores.currency_*` (dead per 16-cleanup-currency.sql),\n//     `orders.shipping_address`/`shipping_zip` (duplicates of the line1/2 +\n//     postalCode block), and the second EAV settings table (`settings` and\n//     `business_settings` are merged into one `Setting` model with a group).\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n}\n\n// ---------------------------------------------------------------------------\n// Stores / settings\n// ---------------------------------------------------------------------------\n\nmodel Store {\n  id          Int      @id @default(autoincrement())\n  name        String   @db.VarChar(100)\n  slug        String   @unique @db.VarChar(100)\n  description String?  @db.Text\n  logo        String?  @db.VarChar(255)\n  email       String?  @db.VarChar(100)\n  phone       String?  @db.VarChar(20)\n  address     String?  @db.Text\n  taxRate     Decimal  @default(0) @map(\"tax_rate\") @db.Decimal(5, 2)\n  isActive    Boolean  @default(true) @map(\"is_active\")\n  isDefault   Boolean  @default(false) @map(\"is_default\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  users             User[]\n  categories        Category[]\n  products          Product[]\n  colors            Color[]\n  sizes             Size[]\n  carts             Cart[]\n  orders            Order[]\n  couriers          Courier[]\n  coupons           Coupon[]\n  returns           Return[]\n  sliders           Slider[]\n  lookbookItems     LookbookItem[]\n  settings          Setting[]\n  socialLinks       SocialLink[]\n  posTerminals      PosTerminal[]\n  posShifts         PosShift[]\n  posTransactions   PosTransaction[]\n  posCashLogs       PosCashLog[]\n  posHeldOrders     PosHeldOrder[]\n  posRefunds        PosRefund[]\n  departments       Department[]\n  employees         Employee[]\n  attendance        Attendance[]\n  leaveTypes        LeaveType[]\n  leaveRequests     LeaveRequest[]\n  salaryComponents  SalaryComponent[]\n  payrollPeriods    PayrollPeriod[]\n  expenseCategories ExpenseCategory[]\n  expenses          Expense[]\n  suppliers         Supplier[]\n  purchaseOrders    PurchaseOrder[]\n  supplierPayments  SupplierPayment[]\n  accounts          Account[]\n  journalEntries    JournalEntry[]\n  campaigns         Campaign[]\n  metaIntegrations  MetaIntegration[]\n  metaMessages      MetaMessage[]\n  metaInsights      MetaPageInsight[]\n  metaTemplates     MetaMessageTemplate[]\n\n  @@map(\"stores\")\n}\n\n/// Merged replacement for the legacy `settings` + `business_settings` EAV tables.\nmodel Setting {\n  id          Int      @id @default(autoincrement())\n  storeId     Int      @map(\"store_id\")\n  key         String   @map(\"setting_key\") @db.VarChar(100)\n  value       String?  @map(\"setting_value\") @db.Text\n  group       String   @default(\"general\") @map(\"setting_group\") @db.VarChar(50)\n  description String?  @db.VarChar(255)\n  isSecret    Boolean  @default(false) @map(\"is_secret\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@unique([storeId, key])\n  @@index([storeId, group])\n  @@map(\"settings\")\n}\n\n// ---------------------------------------------------------------------------\n// Users / auth\n// ---------------------------------------------------------------------------\n\nenum UserRole {\n  CUSTOMER\n  MANAGER\n  ADMIN\n}\n\nmodel User {\n  id              Int       @id @default(autoincrement())\n  storeId         Int?      @map(\"store_id\")\n  name            String    @db.VarChar(100)\n  email           String    @unique @db.VarChar(100)\n  passwordHash    String    @map(\"password\") @db.VarChar(255)\n  phone           String?   @db.VarChar(20)\n  avatar          String?   @db.VarChar(255)\n  role            UserRole  @default(CUSTOMER)\n  isActive        Boolean   @default(true) @map(\"is_active\")\n  emailVerifiedAt DateTime? @map(\"email_verified_at\")\n  lastLoginAt     DateTime? @map(\"last_login\")\n  createdAt       DateTime  @default(now()) @map(\"created_at\")\n  updatedAt       DateTime  @updatedAt @map(\"updated_at\")\n\n  store                  Store?            @relation(fields: [storeId], references: [id], onDelete: SetNull)\n  addresses              Address[]\n  carts                  Cart[]\n  orders                 Order[]\n  wishlist               WishlistItem[]\n  reviews                Review[]\n  employee               Employee?\n  posShifts              PosShift[]\n  posTransactions        PosTransaction[]  @relation(\"PosTransactionCustomer\")\n  posTransactionsCreated PosTransaction[]  @relation(\"PosTransactionCreator\")\n  posCashLogs            PosCashLog[]\n  posHeldOrdersFor       PosHeldOrder[]    @relation(\"PosHeldOrderCustomer\")\n  posHeldOrdersBy        PosHeldOrder[]    @relation(\"PosHeldOrderHolder\")\n  posRefundsFor          PosRefund[]       @relation(\"PosRefundCustomer\")\n  posRefundsBy           PosRefund[]       @relation(\"PosRefundCreator\")\n  leavesApproved         LeaveRequest[]    @relation(\"LeaveApprover\")\n  payrollProcessed       PayrollPeriod[]   @relation(\"PayrollProcessor\")\n  payrollApproved        PayrollPeriod[]   @relation(\"PayrollApprover\")\n  expensesCreated        Expense[]\n  poCreated              PurchaseOrder[]   @relation(\"PoCreator\")\n  poApproved             PurchaseOrder[]   @relation(\"PoApprover\")\n  supplierPayments       SupplierPayment[]\n  journalCreated         JournalEntry[]    @relation(\"JournalCreator\")\n  journalPosted          JournalEntry[]    @relation(\"JournalPoster\")\n  campaigns              Campaign[]\n  campaignNotes          CampaignNote[]\n\n  @@index([storeId])\n  @@map(\"users\")\n}\n\nmodel Address {\n  id           Int      @id @default(autoincrement())\n  userId       Int      @map(\"user_id\")\n  label        String   @default(\"Home\") @db.VarChar(50)\n  name         String   @db.VarChar(100)\n  phone        String?  @db.VarChar(20)\n  addressLine1 String   @map(\"address_line1\") @db.VarChar(255)\n  addressLine2 String?  @map(\"address_line2\") @db.VarChar(255)\n  city         String   @db.VarChar(100)\n  state        String?  @db.VarChar(100)\n  postalCode   String?  @map(\"postal_code\") @db.VarChar(20)\n  country      String   @default(\"Bangladesh\") @db.VarChar(100)\n  isDefault    Boolean  @default(false) @map(\"is_default\")\n  createdAt    DateTime @default(now()) @map(\"created_at\")\n  updatedAt    DateTime @updatedAt @map(\"updated_at\")\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([userId])\n  @@map(\"user_addresses\")\n}\n\n// ---------------------------------------------------------------------------\n// Catalog\n// ---------------------------------------------------------------------------\n\nenum ProductStatus {\n  ACTIVE\n  INACTIVE\n  DRAFT\n}\n\nmodel Category {\n  id          Int      @id @default(autoincrement())\n  storeId     Int      @map(\"store_id\")\n  parentId    Int?     @map(\"parent_id\")\n  name        String   @db.VarChar(100)\n  slug        String   @db.VarChar(100)\n  description String?  @db.Text\n  image       String?  @db.VarChar(255)\n  icon        String?  @db.VarChar(50)\n  sortOrder   Int      @default(0) @map(\"sort_order\")\n  isActive    Boolean  @default(true) @map(\"is_active\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  store    Store      @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  parent   Category?  @relation(\"CategoryTree\", fields: [parentId], references: [id], onDelete: SetNull)\n  children Category[] @relation(\"CategoryTree\")\n  products Product[]\n\n  @@unique([storeId, slug])\n  @@index([parentId])\n  @@map(\"categories\")\n}\n\nmodel Product {\n  id                Int           @id @default(autoincrement())\n  storeId           Int           @map(\"store_id\")\n  categoryId        Int?          @map(\"category_id\")\n  name              String        @db.VarChar(255)\n  slug              String        @db.VarChar(255)\n  description       String?       @db.Text\n  shortDescription  String?       @map(\"short_description\") @db.VarChar(500)\n  price             Decimal       @db.Decimal(12, 2)\n  salePrice         Decimal?      @map(\"sale_price\") @db.Decimal(12, 2)\n  costPrice         Decimal?      @map(\"cost_price\") @db.Decimal(12, 2)\n  sku               String?       @db.VarChar(50)\n  barcode           String?       @db.VarChar(50)\n  stockQuantity     Int           @default(0) @map(\"stock_quantity\")\n  lowStockThreshold Int           @default(5) @map(\"low_stock_threshold\")\n  weight            Decimal?      @db.Decimal(8, 2)\n  isFeatured        Boolean       @default(false) @map(\"is_featured\")\n  isNew             Boolean       @default(false) @map(\"is_new\")\n  status            ProductStatus @default(ACTIVE)\n  metaTitle         String?       @map(\"meta_title\") @db.VarChar(255)\n  metaDescription   String?       @map(\"meta_description\") @db.VarChar(500)\n  views             Int           @default(0)\n  createdAt         DateTime      @default(now()) @map(\"created_at\")\n  updatedAt         DateTime      @updatedAt @map(\"updated_at\")\n\n  store        Store                @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  category     Category?            @relation(fields: [categoryId], references: [id], onDelete: SetNull)\n  images       ProductImage[]\n  variants     ProductVariant[]\n  cartItems    CartItem[]\n  orderItems   OrderItem[]\n  wishlistedBy WishlistItem[]\n  reviews      Review[]\n  giftCoupons  Coupon[]\n  posItems     PosTransactionItem[]\n  poItems      PurchaseOrderItem[]\n\n  @@unique([storeId, slug])\n  @@index([categoryId])\n  @@index([status])\n  @@index([isFeatured])\n  @@index([barcode])\n  @@map(\"products\")\n}\n\nmodel ProductImage {\n  id        Int      @id @default(autoincrement())\n  productId Int      @map(\"product_id\")\n  path      String   @map(\"image_path\") @db.VarChar(255)\n  altText   String?  @map(\"alt_text\") @db.VarChar(255)\n  sortOrder Int      @default(0) @map(\"sort_order\")\n  isPrimary Boolean  @default(false) @map(\"is_primary\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@index([productId, isPrimary])\n  @@map(\"product_images\")\n}\n\nmodel Color {\n  id        Int      @id @default(autoincrement())\n  storeId   Int      @map(\"store_id\")\n  name      String   @db.VarChar(50)\n  hex       String   @map(\"color_code\") @db.VarChar(7)\n  sortOrder Int      @default(0) @map(\"sort_order\")\n  isActive  Boolean  @default(true) @map(\"is_active\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  store    Store            @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  variants ProductVariant[]\n\n  @@unique([storeId, name])\n  @@map(\"product_colors\")\n}\n\nmodel Size {\n  id        Int      @id @default(autoincrement())\n  storeId   Int      @map(\"store_id\")\n  name      String   @db.VarChar(20)\n  sortOrder Int      @default(0) @map(\"sort_order\")\n  isActive  Boolean  @default(true) @map(\"is_active\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@unique([storeId, name])\n  @@map(\"product_sizes\")\n}\n\nmodel ProductVariant {\n  id            Int      @id @default(autoincrement())\n  productId     Int      @map(\"product_id\")\n  colorId       Int?     @map(\"color_id\")\n  size          String?  @db.VarChar(20)\n  colorName     String?  @map(\"color\") @db.VarChar(50)\n  colorHex      String?  @map(\"color_code\") @db.VarChar(7)\n  sku           String?  @db.VarChar(50)\n  priceModifier Decimal  @default(0) @map(\"price_modifier\") @db.Decimal(12, 2)\n  stockQuantity Int      @default(0) @map(\"stock_quantity\")\n  isActive      Boolean  @default(true) @map(\"is_active\")\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n  updatedAt     DateTime @updatedAt @map(\"updated_at\")\n\n  product    Product     @relation(fields: [productId], references: [id], onDelete: Cascade)\n  color      Color?      @relation(fields: [colorId], references: [id], onDelete: SetNull)\n  cartItems  CartItem[]\n  orderItems OrderItem[]\n\n  @@unique([productId, size, colorName])\n  @@index([productId])\n  @@map(\"product_variants\")\n}\n\n// ---------------------------------------------------------------------------\n// Cart / wishlist / reviews\n// ---------------------------------------------------------------------------\n\nmodel Cart {\n  id        Int      @id @default(autoincrement())\n  storeId   Int      @default(1) @map(\"store_id\")\n  userId    Int?     @map(\"user_id\")\n  /// Durable cart cookie token for guests (legacy used the PHP session id,\n  /// which broke the merge-on-login because the id was regenerated first).\n  token     String?  @unique @db.VarChar(64)\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  store Store      @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  user  User?      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  items CartItem[]\n\n  @@index([userId])\n  @@map(\"carts\")\n}\n\nmodel CartItem {\n  id        Int      @id @default(autoincrement())\n  cartId    Int      @map(\"cart_id\")\n  productId Int      @map(\"product_id\")\n  variantId Int?     @map(\"variant_id\")\n  quantity  Int      @default(1)\n  /// Price snapshot at add-time, kept for auditing. Totals always recompute\n  /// from the live product/variant price, matching legacy behaviour.\n  unitPrice Decimal  @map(\"price\") @db.Decimal(12, 2)\n  createdAt DateTime @default(now()) @map(\"created_at\")\n  updatedAt DateTime @updatedAt @map(\"updated_at\")\n\n  cart    Cart            @relation(fields: [cartId], references: [id], onDelete: Cascade)\n  product Product         @relation(fields: [productId], references: [id], onDelete: Cascade)\n  variant ProductVariant? @relation(fields: [variantId], references: [id], onDelete: SetNull)\n\n  @@index([cartId])\n  @@map(\"cart_items\")\n}\n\nmodel WishlistItem {\n  id        Int      @id @default(autoincrement())\n  userId    Int      @map(\"user_id\")\n  productId Int      @map(\"product_id\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, productId])\n  @@map(\"wishlist\")\n}\n\nenum ReviewStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nmodel Review {\n  id        Int          @id @default(autoincrement())\n  productId Int          @map(\"product_id\")\n  userId    Int          @map(\"user_id\")\n  rating    Int          @db.TinyInt\n  title     String?      @db.VarChar(255)\n  comment   String?      @db.Text\n  status    ReviewStatus @default(PENDING)\n  createdAt DateTime     @default(now()) @map(\"created_at\")\n  updatedAt DateTime     @updatedAt @map(\"updated_at\")\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n  user    User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([productId, status])\n  @@map(\"reviews\")\n}\n\n// ---------------------------------------------------------------------------\n// Orders / payments / shipping\n// ---------------------------------------------------------------------------\n\nenum OrderStatus {\n  PENDING\n  PROCESSING\n  SHIPPED\n  DELIVERED\n  CANCELLED\n  REFUNDED\n}\n\nenum PaymentStatus {\n  PENDING\n  PAID\n  FAILED\n  REFUNDED\n}\n\nmodel Order {\n  id             Int           @id @default(autoincrement())\n  storeId        Int           @default(1) @map(\"store_id\")\n  userId         Int?          @map(\"user_id\")\n  orderNumber    String        @unique @map(\"order_number\") @db.VarChar(50)\n  status         OrderStatus   @default(PENDING)\n  paymentStatus  PaymentStatus @default(PENDING) @map(\"payment_status\")\n  paymentMethod  String?       @map(\"payment_method\") @db.VarChar(50)\n  subtotal       Decimal       @db.Decimal(12, 2)\n  couponId       Int?          @map(\"coupon_id\")\n  couponCode     String?       @map(\"coupon_code\") @db.VarChar(50)\n  discountAmount Decimal       @default(0) @map(\"discount_amount\") @db.Decimal(12, 2)\n  taxAmount      Decimal       @default(0) @map(\"tax_amount\") @db.Decimal(12, 2)\n  shippingAmount Decimal       @default(0) @map(\"shipping_amount\") @db.Decimal(12, 2)\n  totalAmount    Decimal       @map(\"total_amount\") @db.Decimal(12, 2)\n\n  shippingName       String? @map(\"shipping_name\") @db.VarChar(100)\n  shippingPhone      String? @map(\"shipping_phone\") @db.VarChar(20)\n  shippingLine1      String? @map(\"shipping_address_line1\") @db.VarChar(255)\n  shippingLine2      String? @map(\"shipping_address_line2\") @db.VarChar(255)\n  shippingCity       String? @map(\"shipping_city\") @db.VarChar(100)\n  shippingState      String? @map(\"shipping_state\") @db.VarChar(100)\n  shippingPostalCode String? @map(\"shipping_postal_code\") @db.VarChar(20)\n  shippingCountry    String? @map(\"shipping_country\") @db.VarChar(100)\n\n  billingName       String? @map(\"billing_name\") @db.VarChar(100)\n  billingPhone      String? @map(\"billing_phone\") @db.VarChar(20)\n  billingLine1      String? @map(\"billing_address_line1\") @db.VarChar(255)\n  billingLine2      String? @map(\"billing_address_line2\") @db.VarChar(255)\n  billingCity       String? @map(\"billing_city\") @db.VarChar(100)\n  billingState      String? @map(\"billing_state\") @db.VarChar(100)\n  billingPostalCode String? @map(\"billing_postal_code\") @db.VarChar(20)\n  billingCountry    String? @map(\"billing_country\") @db.VarChar(100)\n\n  notes      String?  @db.Text\n  adminNotes String?  @map(\"admin_notes\") @db.Text\n  createdAt  DateTime @default(now()) @map(\"created_at\")\n  updatedAt  DateTime @updatedAt @map(\"updated_at\")\n\n  store    Store       @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  user     User?       @relation(fields: [userId], references: [id], onDelete: SetNull)\n  coupon   Coupon?     @relation(fields: [couponId], references: [id], onDelete: SetNull)\n  items    OrderItem[]\n  payments Payment[]\n  shipment Shipment?\n  returns  Return[]\n\n  @@index([storeId, status])\n  @@index([userId])\n  @@index([createdAt])\n  @@map(\"orders\")\n}\n\nmodel OrderItem {\n  id          Int      @id @default(autoincrement())\n  orderId     Int      @map(\"order_id\")\n  productId   Int?     @map(\"product_id\")\n  variantId   Int?     @map(\"variant_id\")\n  productName String   @map(\"product_name\") @db.VarChar(255)\n  productSku  String?  @map(\"product_sku\") @db.VarChar(50)\n  variantInfo String?  @map(\"variant_info\") @db.VarChar(100)\n  quantity    Int\n  unitPrice   Decimal  @map(\"unit_price\") @db.Decimal(12, 2)\n  totalPrice  Decimal  @map(\"total_price\") @db.Decimal(12, 2)\n  isGift      Boolean  @default(false) @map(\"is_gift\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  order   Order           @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  product Product?        @relation(fields: [productId], references: [id], onDelete: SetNull)\n  variant ProductVariant? @relation(fields: [variantId], references: [id], onDelete: SetNull)\n\n  @@index([orderId])\n  @@map(\"order_items\")\n}\n\nmodel Payment {\n  id              Int           @id @default(autoincrement())\n  orderId         Int           @map(\"order_id\")\n  transactionId   String?       @map(\"transaction_id\") @db.VarChar(100)\n  gateway         String        @db.VarChar(50)\n  method          String?       @db.VarChar(50)\n  amount          Decimal       @db.Decimal(12, 2)\n  currency        String        @default(\"BDT\") @db.VarChar(3)\n  status          PaymentStatus @default(PENDING)\n  gatewayResponse Json?         @map(\"gateway_response\")\n  createdAt       DateTime      @default(now()) @map(\"created_at\")\n  updatedAt       DateTime      @updatedAt @map(\"updated_at\")\n\n  order Order @relation(fields: [orderId], references: [id], onDelete: Cascade)\n\n  @@index([orderId])\n  @@map(\"payments\")\n}\n\nmodel Courier {\n  id            Int      @id @default(autoincrement())\n  storeId       Int      @map(\"store_id\")\n  name          String   @db.VarChar(100)\n  code          String   @db.VarChar(50)\n  description   String?  @db.Text\n  logo          String?  @db.VarChar(255)\n  baseRate      Decimal  @default(0) @map(\"base_rate\") @db.Decimal(12, 2)\n  perKgRate     Decimal  @default(0) @map(\"per_kg_rate\") @db.Decimal(12, 2)\n  estimatedDays String?  @map(\"estimated_days\") @db.VarChar(20)\n  trackingUrl   String?  @map(\"tracking_url\") @db.VarChar(255)\n  isActive      Boolean  @default(true) @map(\"is_active\")\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n  updatedAt     DateTime @updatedAt @map(\"updated_at\")\n\n  store     Store      @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  shipments Shipment[]\n\n  @@unique([storeId, code])\n  @@map(\"couriers\")\n}\n\nenum ShipmentStatus {\n  PENDING\n  PICKED_UP\n  IN_TRANSIT\n  OUT_FOR_DELIVERY\n  DELIVERED\n  FAILED\n}\n\nmodel Shipment {\n  id             Int            @id @default(autoincrement())\n  orderId        Int            @unique @map(\"order_id\")\n  courierId      Int?           @map(\"courier_id\")\n  courierName    String?        @map(\"courier_name\") @db.VarChar(100)\n  trackingNumber String?        @map(\"tracking_number\") @db.VarChar(100)\n  status         ShipmentStatus @default(PENDING)\n  deliveryFee    Decimal        @default(0) @map(\"delivery_fee\") @db.Decimal(12, 2)\n  externalStatus String?        @map(\"pathao_status\") @db.VarChar(100)\n  shippedAt      DateTime?      @map(\"shipped_at\")\n  deliveredAt    DateTime?      @map(\"delivered_at\")\n  notes          String?        @db.Text\n  createdAt      DateTime       @default(now()) @map(\"created_at\")\n  updatedAt      DateTime       @updatedAt @map(\"updated_at\")\n\n  order   Order           @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  courier Courier?        @relation(fields: [courierId], references: [id], onDelete: SetNull)\n  events  ShipmentEvent[]\n\n  @@index([trackingNumber])\n  @@map(\"shipments\")\n}\n\nmodel ShipmentEvent {\n  id          Int      @id @default(autoincrement())\n  shipmentId  Int      @map(\"shipment_id\")\n  status      String   @db.VarChar(100)\n  location    String?  @db.VarChar(255)\n  description String?  @db.Text\n  trackedAt   DateTime @default(now()) @map(\"tracked_at\")\n\n  shipment Shipment @relation(fields: [shipmentId], references: [id], onDelete: Cascade)\n\n  @@index([shipmentId])\n  @@map(\"shipment_tracking\")\n}\n\n// ---------------------------------------------------------------------------\n// Returns\n// ---------------------------------------------------------------------------\n\nenum ReturnReason {\n  DEFECTIVE\n  DAMAGED\n  WRONG_ITEM\n  NOT_AS_DESCRIBED\n  CHANGED_MIND\n  CUSTOMER_REFUSED\n  UNDELIVERED\n  OTHER\n}\n\nenum RefundStatus {\n  NOT_REQUIRED\n  PENDING\n  COMPLETED\n}\n\nmodel Return {\n  id            Int          @id @default(autoincrement())\n  storeId       Int          @map(\"store_id\")\n  orderId       Int          @map(\"order_id\")\n  returnNumber  String       @map(\"return_number\") @db.VarChar(50)\n  reason        ReturnReason\n  reasonDetails String?      @map(\"reason_details\") @db.Text\n  refundAmount  Decimal      @default(0) @map(\"refund_amount\") @db.Decimal(12, 2)\n  refundStatus  RefundStatus @default(NOT_REQUIRED) @map(\"refund_status\")\n  adminNotes    String?      @map(\"admin_notes\") @db.Text\n  returnedAt    DateTime     @default(now()) @map(\"returned_at\")\n  createdAt     DateTime     @default(now()) @map(\"created_at\")\n\n  store Store        @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  order Order        @relation(fields: [orderId], references: [id], onDelete: Cascade)\n  items ReturnItem[]\n\n  @@unique([storeId, returnNumber])\n  @@index([orderId])\n  @@map(\"returns\")\n}\n\nmodel ReturnItem {\n  id            Int      @id @default(autoincrement())\n  returnId      Int      @map(\"return_id\")\n  orderItemId   Int?     @map(\"order_item_id\")\n  productId     Int?     @map(\"product_id\")\n  variantId     Int?     @map(\"variant_id\")\n  productName   String?  @map(\"product_name\") @db.VarChar(255)\n  variantInfo   String?  @map(\"variant_info\") @db.VarChar(100)\n  quantity      Int\n  unitPrice     Decimal? @map(\"unit_price\") @db.Decimal(12, 2)\n  stockRestored Boolean  @default(true) @map(\"stock_restored\")\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  return Return @relation(fields: [returnId], references: [id], onDelete: Cascade)\n\n  @@index([returnId])\n  @@map(\"return_items\")\n}\n\n// ---------------------------------------------------------------------------\n// Coupons\n// ---------------------------------------------------------------------------\n\nenum CouponType {\n  FIXED\n  PERCENTAGE\n  FREE_SHIPPING\n  GIFT_ITEM\n  BUY_X_GET_Y\n}\n\nmodel Coupon {\n  id              Int        @id @default(autoincrement())\n  storeId         Int        @map(\"store_id\")\n  code            String     @db.VarChar(50)\n  type            CouponType @default(FIXED)\n  value           Decimal    @default(0) @db.Decimal(12, 2)\n  minimumAmount   Decimal    @default(0) @map(\"minimum_amount\") @db.Decimal(12, 2)\n  maximumDiscount Decimal?   @map(\"maximum_discount\") @db.Decimal(12, 2)\n  giftProductId   Int?       @map(\"gift_product_id\")\n  buyQuantity     Int?       @map(\"buy_quantity\")\n  getQuantity     Int?       @map(\"get_quantity\")\n  usageLimit      Int?       @map(\"usage_limit\")\n  usedCount       Int        @default(0) @map(\"used_count\")\n  startsAt        DateTime?  @map(\"starts_at\")\n  expiresAt       DateTime?  @map(\"expires_at\")\n  isActive        Boolean    @default(true) @map(\"is_active\")\n  createdAt       DateTime   @default(now()) @map(\"created_at\")\n  updatedAt       DateTime   @updatedAt @map(\"updated_at\")\n\n  store       Store    @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  giftProduct Product? @relation(fields: [giftProductId], references: [id], onDelete: SetNull)\n  orders      Order[]\n\n  @@unique([storeId, code])\n  @@map(\"coupons\")\n}\n\n// ---------------------------------------------------------------------------\n// Content (sliders / lookbook / social)\n// ---------------------------------------------------------------------------\n\nenum TextPosition {\n  LEFT\n  CENTER\n  RIGHT\n}\n\nmodel Slider {\n  id             Int          @id @default(autoincrement())\n  storeId        Int          @map(\"store_id\")\n  title          String       @db.VarChar(255)\n  subtitle       String?      @db.VarChar(255)\n  description    String?      @db.Text\n  buttonText     String?      @map(\"button_text\") @db.VarChar(100)\n  buttonLink     String?      @map(\"button_link\") @db.VarChar(255)\n  button2Text    String?      @map(\"button2_text\") @db.VarChar(100)\n  button2Link    String?      @map(\"button2_link\") @db.VarChar(255)\n  image          String?      @db.VarChar(255)\n  textPosition   TextPosition @default(LEFT) @map(\"text_position\")\n  textColor      String       @default(\"#ffffff\") @map(\"text_color\") @db.VarChar(20)\n  overlayOpacity Decimal      @default(0.40) @map(\"overlay_opacity\") @db.Decimal(3, 2)\n  sortOrder      Int          @default(0) @map(\"sort_order\")\n  isActive       Boolean      @default(true) @map(\"is_active\")\n  createdAt      DateTime     @default(now()) @map(\"created_at\")\n  updatedAt      DateTime     @updatedAt @map(\"updated_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@index([storeId, isActive, sortOrder])\n  @@map(\"sliders\")\n}\n\nmodel LookbookItem {\n  id         Int      @id @default(autoincrement())\n  storeId    Int      @map(\"store_id\")\n  image      String   @db.VarChar(255)\n  link       String?  @db.VarChar(255)\n  caption    String?  @db.VarChar(255)\n  isFeatured Boolean  @default(false) @map(\"is_featured\")\n  sortOrder  Int      @default(0) @map(\"sort_order\")\n  isActive   Boolean  @default(true) @map(\"is_active\")\n  createdAt  DateTime @default(now()) @map(\"created_at\")\n  updatedAt  DateTime @updatedAt @map(\"updated_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@index([storeId, isActive, sortOrder])\n  @@map(\"lookbook\")\n}\n\nenum IconStyle {\n  BRANDS\n  SOLID\n  REGULAR\n}\n\nmodel SocialLink {\n  id           Int       @id @default(autoincrement())\n  storeId      Int       @map(\"store_id\")\n  platform     String    @db.VarChar(50)\n  name         String    @db.VarChar(100)\n  url          String    @db.VarChar(500)\n  icon         String    @db.VarChar(100)\n  iconStyle    IconStyle @default(BRANDS) @map(\"icon_style\")\n  color        String    @default(\"#000000\") @db.VarChar(20)\n  sortOrder    Int       @default(0) @map(\"sort_order\")\n  isActive     Boolean   @default(true) @map(\"is_active\")\n  showInHeader Boolean   @default(false) @map(\"show_in_header\")\n  showInFooter Boolean   @default(true) @map(\"show_in_footer\")\n  openNewTab   Boolean   @default(true) @map(\"open_new_tab\")\n  createdAt    DateTime  @default(now()) @map(\"created_at\")\n  updatedAt    DateTime  @updatedAt @map(\"updated_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@index([storeId, isActive, sortOrder])\n  @@map(\"social_media\")\n}\n\n// ---------------------------------------------------------------------------\n// POS\n// ---------------------------------------------------------------------------\n\nenum PosShiftStatus {\n  OPEN\n  CLOSED\n}\n\nenum PosPaymentMethod {\n  CASH\n  CARD\n  MOBILE_BANKING\n  MIXED\n}\n\nenum PosTransactionStatus {\n  COMPLETED\n  REFUNDED\n  VOID\n}\n\nenum PosCashLogType {\n  CASH_IN\n  CASH_OUT\n  ADJUSTMENT\n}\n\nenum PosHeldOrderStatus {\n  HELD\n  RECALLED\n  EXPIRED\n}\n\nenum PosRefundMethod {\n  CASH\n  CARD\n  STORE_CREDIT\n  ORIGINAL_METHOD\n}\n\nenum PosRefundStatus {\n  PENDING\n  COMPLETED\n  CANCELLED\n}\n\nmodel PosTerminal {\n  id        Int      @id @default(autoincrement())\n  storeId   Int      @map(\"store_id\")\n  name      String   @map(\"terminal_name\") @db.VarChar(100)\n  code      String   @map(\"terminal_code\") @db.VarChar(20)\n  location  String?  @db.VarChar(255)\n  isActive  Boolean  @default(true) @map(\"is_active\")\n  createdAt DateTime @default(now()) @map(\"created_at\")\n\n  store        Store            @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  shifts       PosShift[]\n  transactions PosTransaction[]\n  heldOrders   PosHeldOrder[]\n  refunds      PosRefund[]\n\n  @@unique([storeId, code])\n  @@map(\"pos_terminals\")\n}\n\nmodel PosShift {\n  id                Int            @id @default(autoincrement())\n  storeId           Int            @map(\"store_id\")\n  terminalId        Int            @map(\"terminal_id\")\n  userId            Int            @map(\"user_id\")\n  shiftNumber       String         @unique @map(\"shift_number\") @db.VarChar(50)\n  openingTime       DateTime       @map(\"opening_time\")\n  closingTime       DateTime?      @map(\"closing_time\")\n  openingCash       Decimal        @default(0) @map(\"opening_cash\") @db.Decimal(12, 2)\n  expectedCash      Decimal        @default(0) @map(\"expected_cash\") @db.Decimal(12, 2)\n  actualCash        Decimal        @default(0) @map(\"actual_cash\") @db.Decimal(12, 2)\n  cashDifference    Decimal        @default(0) @map(\"cash_difference\") @db.Decimal(12, 2)\n  totalSales        Decimal        @default(0) @map(\"total_sales\") @db.Decimal(14, 2)\n  totalTransactions Int            @default(0) @map(\"total_transactions\")\n  totalRefunds      Decimal        @default(0) @map(\"total_refunds\") @db.Decimal(12, 2)\n  status            PosShiftStatus @default(OPEN)\n  notes             String?        @db.Text\n  createdAt         DateTime       @default(now()) @map(\"created_at\")\n\n  store        Store            @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  terminal     PosTerminal      @relation(fields: [terminalId], references: [id], onDelete: Cascade)\n  user         User             @relation(fields: [userId], references: [id], onDelete: Cascade)\n  transactions PosTransaction[]\n  cashLogs     PosCashLog[]\n  heldOrders   PosHeldOrder[]\n  refunds      PosRefund[]\n\n  @@index([storeId, status])\n  @@map(\"pos_shifts\")\n}\n\nmodel PosTransaction {\n  id                Int                  @id @default(autoincrement())\n  storeId           Int                  @map(\"store_id\")\n  shiftId           Int?                 @map(\"shift_id\")\n  terminalId        Int?                 @map(\"terminal_id\")\n  transactionNumber String               @unique @map(\"transaction_number\") @db.VarChar(50)\n  customerId        Int?                 @map(\"customer_id\")\n  customerName      String?              @map(\"customer_name\") @db.VarChar(255)\n  customerPhone     String?              @map(\"customer_phone\") @db.VarChar(50)\n  subtotal          Decimal              @db.Decimal(14, 2)\n  discountAmount    Decimal              @default(0) @map(\"discount_amount\") @db.Decimal(12, 2)\n  taxAmount         Decimal              @default(0) @map(\"tax_amount\") @db.Decimal(12, 2)\n  totalAmount       Decimal              @map(\"total_amount\") @db.Decimal(14, 2)\n  paymentMethod     PosPaymentMethod     @default(CASH) @map(\"payment_method\")\n  cashReceived      Decimal              @default(0) @map(\"cash_received\") @db.Decimal(14, 2)\n  changeAmount      Decimal              @default(0) @map(\"change_amount\") @db.Decimal(12, 2)\n  cardAmount        Decimal              @default(0) @map(\"card_amount\") @db.Decimal(14, 2)\n  mobileAmount      Decimal              @default(0) @map(\"mobile_amount\") @db.Decimal(14, 2)\n  status            PosTransactionStatus @default(COMPLETED)\n  refundedAmount    Decimal              @default(0) @map(\"refunded_amount\") @db.Decimal(14, 2)\n  notes             String?              @db.Text\n  createdById       Int?                 @map(\"created_by\")\n  createdAt         DateTime             @default(now()) @map(\"created_at\")\n\n  store         Store                @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  shift         PosShift?            @relation(fields: [shiftId], references: [id], onDelete: SetNull)\n  terminal      PosTerminal?         @relation(fields: [terminalId], references: [id], onDelete: SetNull)\n  customer      User?                @relation(\"PosTransactionCustomer\", fields: [customerId], references: [id], onDelete: SetNull)\n  createdBy     User?                @relation(\"PosTransactionCreator\", fields: [createdById], references: [id], onDelete: SetNull)\n  items         PosTransactionItem[]\n  splitPayments PosSplitPayment[]\n  refunds       PosRefund[]\n\n  @@index([storeId, createdAt])\n  @@map(\"pos_transactions\")\n}\n\nmodel PosTransactionItem {\n  id            Int      @id @default(autoincrement())\n  transactionId Int      @map(\"transaction_id\")\n  productId     Int?     @map(\"product_id\")\n  productName   String   @map(\"product_name\") @db.VarChar(255)\n  productSku    String?  @map(\"product_sku\") @db.VarChar(100)\n  variantId     Int?     @map(\"variant_id\")\n  variantInfo   String?  @map(\"variant_info\") @db.VarChar(255)\n  quantity      Int\n  unitPrice     Decimal  @map(\"unit_price\") @db.Decimal(12, 2)\n  discount      Decimal  @default(0) @db.Decimal(12, 2)\n  totalPrice    Decimal  @map(\"total_price\") @db.Decimal(14, 2)\n  createdAt     DateTime @default(now()) @map(\"created_at\")\n\n  transaction PosTransaction @relation(fields: [transactionId], references: [id], onDelete: Cascade)\n  product     Product?       @relation(fields: [productId], references: [id], onDelete: SetNull)\n\n  @@index([transactionId])\n  @@map(\"pos_transaction_items\")\n}\n\nmodel PosCashLog {\n  id          Int            @id @default(autoincrement())\n  storeId     Int            @map(\"store_id\")\n  shiftId     Int            @map(\"shift_id\")\n  type        PosCashLogType @map(\"log_type\")\n  amount      Decimal        @db.Decimal(12, 2)\n  reason      String?        @db.VarChar(255)\n  reference   String?        @db.VarChar(100)\n  createdById Int?           @map(\"created_by\")\n  createdAt   DateTime       @default(now()) @map(\"created_at\")\n\n  store     Store    @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  shift     PosShift @relation(fields: [shiftId], references: [id], onDelete: Cascade)\n  createdBy User?    @relation(fields: [createdById], references: [id], onDelete: SetNull)\n\n  @@index([shiftId])\n  @@map(\"pos_cash_logs\")\n}\n\nmodel PosHeldOrder {\n  id            Int                @id @default(autoincrement())\n  storeId       Int                @map(\"store_id\")\n  shiftId       Int?               @map(\"shift_id\")\n  terminalId    Int?               @map(\"terminal_id\")\n  holdNumber    String             @unique @map(\"hold_number\") @db.VarChar(50)\n  customerId    Int?               @map(\"customer_id\")\n  customerName  String?            @map(\"customer_name\") @db.VarChar(255)\n  customerPhone String?            @map(\"customer_phone\") @db.VarChar(50)\n  items         Json               @map(\"items_json\")\n  note          String?            @db.Text\n  status        PosHeldOrderStatus @default(HELD)\n  heldById      Int?               @map(\"held_by\")\n  recalledAt    DateTime?          @map(\"recalled_at\")\n  expiresAt     DateTime?          @map(\"expires_at\")\n  createdAt     DateTime           @default(now()) @map(\"created_at\")\n\n  store    Store        @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  shift    PosShift?    @relation(fields: [shiftId], references: [id], onDelete: SetNull)\n  terminal PosTerminal? @relation(fields: [terminalId], references: [id], onDelete: SetNull)\n  customer User?        @relation(\"PosHeldOrderCustomer\", fields: [customerId], references: [id], onDelete: SetNull)\n  heldBy   User?        @relation(\"PosHeldOrderHolder\", fields: [heldById], references: [id], onDelete: SetNull)\n\n  @@index([storeId, status])\n  @@map(\"pos_held_orders\")\n}\n\nmodel PosRefund {\n  id            Int             @id @default(autoincrement())\n  storeId       Int             @map(\"store_id\")\n  shiftId       Int?            @map(\"shift_id\")\n  terminalId    Int?            @map(\"terminal_id\")\n  transactionId Int             @map(\"transaction_id\")\n  refundNumber  String          @unique @map(\"refund_number\") @db.VarChar(50)\n  customerId    Int?            @map(\"customer_id\")\n  customerName  String?         @map(\"customer_name\") @db.VarChar(255)\n  refundAmount  Decimal         @map(\"refund_amount\") @db.Decimal(14, 2)\n  refundMethod  PosRefundMethod @default(CASH) @map(\"refund_method\")\n  reason        String?         @db.VarChar(100)\n  items         Json?           @map(\"items_json\")\n  notes         String?         @db.Text\n  status        PosRefundStatus @default(COMPLETED)\n  createdById   Int?            @map(\"created_by\")\n  createdAt     DateTime        @default(now()) @map(\"created_at\")\n\n  store       Store          @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  shift       PosShift?      @relation(fields: [shiftId], references: [id], onDelete: SetNull)\n  terminal    PosTerminal?   @relation(fields: [terminalId], references: [id], onDelete: SetNull)\n  transaction PosTransaction @relation(fields: [transactionId], references: [id], onDelete: Cascade)\n  customer    User?          @relation(\"PosRefundCustomer\", fields: [customerId], references: [id], onDelete: SetNull)\n  createdBy   User?          @relation(\"PosRefundCreator\", fields: [createdById], references: [id], onDelete: SetNull)\n\n  @@index([storeId, status])\n  @@map(\"pos_refunds\")\n}\n\nmodel PosSplitPayment {\n  id              Int              @id @default(autoincrement())\n  transactionId   Int              @map(\"transaction_id\")\n  paymentMethod   PosPaymentMethod @map(\"payment_method\")\n  amount          Decimal          @db.Decimal(14, 2)\n  referenceNumber String?          @map(\"reference_number\") @db.VarChar(100)\n  createdAt       DateTime         @default(now()) @map(\"created_at\")\n\n  transaction PosTransaction @relation(fields: [transactionId], references: [id], onDelete: Cascade)\n\n  @@index([transactionId])\n  @@map(\"pos_split_payments\")\n}\n\n// ---------------------------------------------------------------------------\n// HR\n// ---------------------------------------------------------------------------\n\nenum Gender {\n  MALE\n  FEMALE\n  OTHER\n}\n\nenum EmploymentType {\n  FULL_TIME\n  PART_TIME\n  CONTRACT\n  INTERN\n}\n\nenum EmployeeStatus {\n  ACTIVE\n  ON_LEAVE\n  TERMINATED\n  RESIGNED\n}\n\nenum AttendanceStatus {\n  PRESENT\n  ABSENT\n  LATE\n  HALF_DAY\n  LEAVE\n  HOLIDAY\n}\n\nenum LeaveStatus {\n  PENDING\n  APPROVED\n  REJECTED\n  CANCELLED\n}\n\nenum SalaryComponentType {\n  EARNING\n  DEDUCTION\n}\n\nenum SalaryCalculationType {\n  FIXED\n  PERCENTAGE\n}\n\nenum PayrollPeriodStatus {\n  DRAFT\n  PROCESSING\n  APPROVED\n  PAID\n  CANCELLED\n}\n\nenum PayrollPaymentMethod {\n  BANK\n  CASH\n  MOBILE_BANKING\n}\n\nenum PayrollPaymentStatus {\n  PENDING\n  PAID\n}\n\nmodel Department {\n  id          Int      @id @default(autoincrement())\n  storeId     Int      @map(\"store_id\")\n  name        String   @db.VarChar(100)\n  code        String?  @db.VarChar(20)\n  description String?  @db.Text\n  managerId   Int?     @map(\"manager_id\")\n  isActive    Boolean  @default(true) @map(\"is_active\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  store     Store      @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  employees Employee[]\n\n  @@index([storeId])\n  @@map(\"departments\")\n}\n\nmodel Employee {\n  id                    Int            @id @default(autoincrement())\n  storeId               Int            @map(\"store_id\")\n  userId                Int?           @unique @map(\"user_id\")\n  /// Human-facing employee code (e.g. \"EMP-001\") — not a foreign key.\n  code                  String         @map(\"employee_id\") @db.VarChar(20)\n  firstName             String         @map(\"first_name\") @db.VarChar(100)\n  lastName              String?        @map(\"last_name\") @db.VarChar(100)\n  email                 String?        @db.VarChar(255)\n  phone                 String?        @db.VarChar(50)\n  dateOfBirth           DateTime?      @map(\"date_of_birth\") @db.Date\n  gender                Gender?\n  nationalId            String?        @map(\"national_id\") @db.VarChar(50)\n  address               String?        @db.Text\n  city                  String?        @db.VarChar(100)\n  departmentId          Int?           @map(\"department_id\")\n  designation           String?        @db.VarChar(100)\n  employmentType        EmploymentType @default(FULL_TIME) @map(\"employment_type\")\n  hireDate              DateTime       @map(\"hire_date\") @db.Date\n  terminationDate       DateTime?      @map(\"termination_date\") @db.Date\n  basicSalary           Decimal        @default(0) @map(\"basic_salary\") @db.Decimal(12, 2)\n  bankName              String?        @map(\"bank_name\") @db.VarChar(100)\n  bankAccount           String?        @map(\"bank_account\") @db.VarChar(50)\n  mobileBanking         String?        @map(\"mobile_banking\") @db.VarChar(50)\n  emergencyContactName  String?        @map(\"emergency_contact_name\") @db.VarChar(255)\n  emergencyContactPhone String?        @map(\"emergency_contact_phone\") @db.VarChar(50)\n  photo                 String?        @db.VarChar(255)\n  status                EmployeeStatus @default(ACTIVE)\n  notes                 String?        @db.Text\n  createdAt             DateTime       @default(now()) @map(\"created_at\")\n  updatedAt             DateTime       @updatedAt @map(\"updated_at\")\n\n  store           Store                     @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  user            User?                     @relation(fields: [userId], references: [id], onDelete: SetNull)\n  department      Department?               @relation(fields: [departmentId], references: [id], onDelete: SetNull)\n  attendance      Attendance[]\n  leaveRequests   LeaveRequest[]\n  salaryStructure EmployeeSalaryComponent[]\n  payrollDetails  PayrollDetail[]\n\n  @@unique([storeId, code])\n  @@index([departmentId])\n  @@map(\"employees\")\n}\n\nmodel Attendance {\n  id            Int              @id @default(autoincrement())\n  storeId       Int              @map(\"store_id\")\n  employeeId    Int              @map(\"employee_id\")\n  date          DateTime         @map(\"attendance_date\") @db.Date\n  checkIn       DateTime?        @map(\"check_in\") @db.Time()\n  checkOut      DateTime?        @map(\"check_out\") @db.Time()\n  status        AttendanceStatus @default(PRESENT)\n  workHours     Decimal          @default(0) @map(\"work_hours\") @db.Decimal(4, 2)\n  overtimeHours Decimal          @default(0) @map(\"overtime_hours\") @db.Decimal(4, 2)\n  notes         String?          @db.Text\n  createdAt     DateTime         @default(now()) @map(\"created_at\")\n\n  store    Store    @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  employee Employee @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n\n  @@unique([employeeId, date])\n  @@index([storeId, date])\n  @@map(\"attendance\")\n}\n\nmodel LeaveType {\n  id          Int      @id @default(autoincrement())\n  storeId     Int      @map(\"store_id\")\n  name        String   @db.VarChar(100)\n  daysPerYear Int      @default(0) @map(\"days_per_year\")\n  isPaid      Boolean  @default(true) @map(\"is_paid\")\n  isActive    Boolean  @default(true) @map(\"is_active\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n\n  store    Store          @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  requests LeaveRequest[]\n\n  @@index([storeId])\n  @@map(\"leave_types\")\n}\n\nmodel LeaveRequest {\n  id              Int         @id @default(autoincrement())\n  storeId         Int         @map(\"store_id\")\n  employeeId      Int         @map(\"employee_id\")\n  leaveTypeId     Int         @map(\"leave_type_id\")\n  startDate       DateTime    @map(\"start_date\") @db.Date\n  endDate         DateTime    @map(\"end_date\") @db.Date\n  days            Int\n  reason          String?     @db.Text\n  status          LeaveStatus @default(PENDING)\n  approvedById    Int?        @map(\"approved_by\")\n  approvedAt      DateTime?   @map(\"approved_at\")\n  rejectionReason String?     @map(\"rejection_reason\") @db.Text\n  createdAt       DateTime    @default(now()) @map(\"created_at\")\n\n  store      Store     @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  employee   Employee  @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  leaveType  LeaveType @relation(fields: [leaveTypeId], references: [id], onDelete: Cascade)\n  approvedBy User?     @relation(\"LeaveApprover\", fields: [approvedById], references: [id], onDelete: SetNull)\n\n  @@index([employeeId, status])\n  @@map(\"leave_requests\")\n}\n\nmodel SalaryComponent {\n  id              Int                   @id @default(autoincrement())\n  storeId         Int                   @map(\"store_id\")\n  name            String                @db.VarChar(100)\n  type            SalaryComponentType\n  calculationType SalaryCalculationType @default(FIXED) @map(\"calculation_type\")\n  defaultAmount   Decimal               @default(0) @map(\"default_amount\") @db.Decimal(12, 2)\n  percentageOf    String?               @map(\"percentage_of\") @db.VarChar(50)\n  isTaxable       Boolean               @default(false) @map(\"is_taxable\")\n  isActive        Boolean               @default(true) @map(\"is_active\")\n  createdAt       DateTime              @default(now()) @map(\"created_at\")\n\n  store            Store                     @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  employeeSalaries EmployeeSalaryComponent[]\n  payrollLines     PayrollDetailComponent[]\n\n  @@index([storeId])\n  @@map(\"salary_components\")\n}\n\nmodel EmployeeSalaryComponent {\n  id            Int       @id @default(autoincrement())\n  employeeId    Int       @map(\"employee_id\")\n  componentId   Int       @map(\"component_id\")\n  amount        Decimal   @db.Decimal(12, 2)\n  effectiveFrom DateTime  @map(\"effective_from\") @db.Date\n  effectiveTo   DateTime? @map(\"effective_to\") @db.Date\n  createdAt     DateTime  @default(now()) @map(\"created_at\")\n\n  employee  Employee        @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  component SalaryComponent @relation(fields: [componentId], references: [id], onDelete: Cascade)\n\n  @@index([employeeId])\n  @@map(\"employee_salary_structure\")\n}\n\nmodel PayrollPeriod {\n  id              Int                 @id @default(autoincrement())\n  storeId         Int                 @map(\"store_id\")\n  name            String              @map(\"period_name\") @db.VarChar(100)\n  startDate       DateTime            @map(\"start_date\") @db.Date\n  endDate         DateTime            @map(\"end_date\") @db.Date\n  payDate         DateTime?           @map(\"pay_date\") @db.Date\n  status          PayrollPeriodStatus @default(DRAFT)\n  totalEmployees  Int                 @default(0) @map(\"total_employees\")\n  totalGross      Decimal             @default(0) @map(\"total_gross\") @db.Decimal(14, 2)\n  totalDeductions Decimal             @default(0) @map(\"total_deductions\") @db.Decimal(14, 2)\n  totalNet        Decimal             @default(0) @map(\"total_net\") @db.Decimal(14, 2)\n  processedById   Int?                @map(\"processed_by\")\n  processedAt     DateTime?           @map(\"processed_at\")\n  approvedById    Int?                @map(\"approved_by\")\n  approvedAt      DateTime?           @map(\"approved_at\")\n  createdAt       DateTime            @default(now()) @map(\"created_at\")\n\n  store       Store           @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  processedBy User?           @relation(\"PayrollProcessor\", fields: [processedById], references: [id], onDelete: SetNull)\n  approvedBy  User?           @relation(\"PayrollApprover\", fields: [approvedById], references: [id], onDelete: SetNull)\n  details     PayrollDetail[]\n\n  @@index([storeId, status])\n  @@map(\"payroll_periods\")\n}\n\nmodel PayrollDetail {\n  id              Int                  @id @default(autoincrement())\n  payrollPeriodId Int                  @map(\"payroll_period_id\")\n  employeeId      Int                  @map(\"employee_id\")\n  basicSalary     Decimal              @default(0) @map(\"basic_salary\") @db.Decimal(12, 2)\n  workingDays     Int                  @default(0) @map(\"working_days\")\n  presentDays     Int                  @default(0) @map(\"present_days\")\n  absentDays      Int                  @default(0) @map(\"absent_days\")\n  leaveDays       Int                  @default(0) @map(\"leave_days\")\n  overtimeHours   Decimal              @default(0) @map(\"overtime_hours\") @db.Decimal(6, 2)\n  overtimeAmount  Decimal              @default(0) @map(\"overtime_amount\") @db.Decimal(12, 2)\n  grossEarnings   Decimal              @default(0) @map(\"gross_earnings\") @db.Decimal(14, 2)\n  totalDeductions Decimal              @default(0) @map(\"total_deductions\") @db.Decimal(14, 2)\n  netSalary       Decimal              @default(0) @map(\"net_salary\") @db.Decimal(14, 2)\n  paymentMethod   PayrollPaymentMethod @default(BANK) @map(\"payment_method\")\n  paymentStatus   PayrollPaymentStatus @default(PENDING) @map(\"payment_status\")\n  paidAt          DateTime?            @map(\"paid_at\")\n  notes           String?              @db.Text\n  createdAt       DateTime             @default(now()) @map(\"created_at\")\n\n  period     PayrollPeriod            @relation(fields: [payrollPeriodId], references: [id], onDelete: Cascade)\n  employee   Employee                 @relation(fields: [employeeId], references: [id], onDelete: Cascade)\n  components PayrollDetailComponent[]\n\n  @@unique([payrollPeriodId, employeeId])\n  @@map(\"payroll_details\")\n}\n\nmodel PayrollDetailComponent {\n  id              Int                 @id @default(autoincrement())\n  payrollDetailId Int                 @map(\"payroll_detail_id\")\n  componentId     Int                 @map(\"component_id\")\n  componentName   String              @map(\"component_name\") @db.VarChar(100)\n  componentType   SalaryComponentType @map(\"component_type\")\n  amount          Decimal             @db.Decimal(12, 2)\n  createdAt       DateTime            @default(now()) @map(\"created_at\")\n\n  payrollDetail PayrollDetail   @relation(fields: [payrollDetailId], references: [id], onDelete: Cascade)\n  component     SalaryComponent @relation(fields: [componentId], references: [id], onDelete: Cascade)\n\n  @@index([payrollDetailId])\n  @@map(\"payroll_detail_components\")\n}\n\n// ---------------------------------------------------------------------------\n// Expenses / purchasing\n// ---------------------------------------------------------------------------\n\nenum ExpensePaymentMethod {\n  CASH\n  BANK_TRANSFER\n  MOBILE_BANKING\n  CARD\n  OTHER\n}\n\nenum ExpensePaymentStatus {\n  PENDING\n  PAID\n  PARTIAL\n}\n\nmodel ExpenseCategory {\n  id          Int      @id @default(autoincrement())\n  storeId     Int      @map(\"store_id\")\n  name        String   @db.VarChar(100)\n  slug        String   @db.VarChar(100)\n  description String?  @db.Text\n  color       String   @default(\"#6c757d\") @db.VarChar(7)\n  icon        String   @default(\"tag\") @db.VarChar(50)\n  isActive    Boolean  @default(true) @map(\"is_active\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  store    Store     @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  expenses Expense[]\n\n  @@unique([storeId, slug])\n  @@map(\"expense_categories\")\n}\n\nmodel Expense {\n  id              Int                  @id @default(autoincrement())\n  storeId         Int                  @map(\"store_id\")\n  categoryId      Int?                 @map(\"category_id\")\n  expenseNumber   String               @unique @map(\"expense_number\") @db.VarChar(50)\n  title           String               @db.VarChar(255)\n  description     String?              @db.Text\n  amount          Decimal              @db.Decimal(12, 2)\n  taxAmount       Decimal              @default(0) @map(\"tax_amount\") @db.Decimal(12, 2)\n  totalAmount     Decimal              @map(\"total_amount\") @db.Decimal(12, 2)\n  expenseDate     DateTime             @map(\"expense_date\") @db.Date\n  paymentMethod   ExpensePaymentMethod @default(CASH) @map(\"payment_method\")\n  paymentStatus   ExpensePaymentStatus @default(PENDING) @map(\"payment_status\")\n  referenceNumber String?              @map(\"reference_number\") @db.VarChar(100)\n  vendorName      String?              @map(\"vendor_name\") @db.VarChar(255)\n  receiptPath     String?              @map(\"receipt_path\") @db.VarChar(255)\n  notes           String?              @db.Text\n  createdById     Int?                 @map(\"created_by\")\n  createdAt       DateTime             @default(now()) @map(\"created_at\")\n  updatedAt       DateTime             @updatedAt @map(\"updated_at\")\n\n  store     Store            @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  category  ExpenseCategory? @relation(fields: [categoryId], references: [id], onDelete: SetNull)\n  createdBy User?            @relation(fields: [createdById], references: [id], onDelete: SetNull)\n\n  @@index([storeId, expenseDate])\n  @@index([paymentStatus])\n  @@map(\"expenses\")\n}\n\nenum SupplierStatus {\n  ACTIVE\n  INACTIVE\n}\n\nenum PurchaseOrderStatus {\n  DRAFT\n  PENDING\n  APPROVED\n  ORDERED\n  PARTIAL\n  RECEIVED\n  CANCELLED\n}\n\nenum PurchasePaymentStatus {\n  PENDING\n  PARTIAL\n  PAID\n}\n\nenum SupplierPaymentMethod {\n  CASH\n  BANK_TRANSFER\n  CHECK\n  MOBILE_BANKING\n  OTHER\n}\n\nmodel Supplier {\n  id             Int            @id @default(autoincrement())\n  storeId        Int            @map(\"store_id\")\n  name           String         @db.VarChar(255)\n  code           String?        @db.VarChar(50)\n  contactPerson  String?        @map(\"contact_person\") @db.VarChar(255)\n  email          String?        @db.VarChar(255)\n  phone          String?        @db.VarChar(50)\n  address        String?        @db.Text\n  city           String?        @db.VarChar(100)\n  country        String         @default(\"Bangladesh\") @db.VarChar(100)\n  paymentTerms   Int            @default(30) @map(\"payment_terms\")\n  notes          String?        @db.Text\n  status         SupplierStatus @default(ACTIVE)\n  totalPurchases Decimal        @default(0) @map(\"total_purchases\") @db.Decimal(14, 2)\n  totalPaid      Decimal        @default(0) @map(\"total_paid\") @db.Decimal(14, 2)\n  createdAt      DateTime       @default(now()) @map(\"created_at\")\n  updatedAt      DateTime       @updatedAt @map(\"updated_at\")\n\n  store          Store             @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  purchaseOrders PurchaseOrder[]\n  payments       SupplierPayment[]\n\n  @@index([storeId, status])\n  @@index([name])\n  @@map(\"suppliers\")\n}\n\nmodel PurchaseOrder {\n  id             Int                   @id @default(autoincrement())\n  storeId        Int                   @map(\"store_id\")\n  supplierId     Int                   @map(\"supplier_id\")\n  poNumber       String                @unique @map(\"po_number\") @db.VarChar(50)\n  status         PurchaseOrderStatus   @default(DRAFT)\n  orderDate      DateTime              @map(\"order_date\") @db.Date\n  expectedDate   DateTime?             @map(\"expected_date\") @db.Date\n  receivedDate   DateTime?             @map(\"received_date\") @db.Date\n  subtotal       Decimal               @default(0) @db.Decimal(14, 2)\n  taxAmount      Decimal               @default(0) @map(\"tax_amount\") @db.Decimal(12, 2)\n  shippingAmount Decimal               @default(0) @map(\"shipping_amount\") @db.Decimal(12, 2)\n  discountAmount Decimal               @default(0) @map(\"discount_amount\") @db.Decimal(12, 2)\n  totalAmount    Decimal               @default(0) @map(\"total_amount\") @db.Decimal(14, 2)\n  paymentStatus  PurchasePaymentStatus @default(PENDING) @map(\"payment_status\")\n  paidAmount     Decimal               @default(0) @map(\"paid_amount\") @db.Decimal(14, 2)\n  notes          String?               @db.Text\n  createdById    Int?                  @map(\"created_by\")\n  approvedById   Int?                  @map(\"approved_by\")\n  approvedAt     DateTime?             @map(\"approved_at\")\n  createdAt      DateTime              @default(now()) @map(\"created_at\")\n  updatedAt      DateTime              @updatedAt @map(\"updated_at\")\n\n  store      Store               @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  supplier   Supplier            @relation(fields: [supplierId], references: [id], onDelete: Restrict)\n  createdBy  User?               @relation(\"PoCreator\", fields: [createdById], references: [id], onDelete: SetNull)\n  approvedBy User?               @relation(\"PoApprover\", fields: [approvedById], references: [id], onDelete: SetNull)\n  items      PurchaseOrderItem[]\n  payments   SupplierPayment[]\n\n  @@index([storeId, status])\n  @@index([supplierId])\n  @@map(\"purchase_orders\")\n}\n\nmodel PurchaseOrderItem {\n  id               Int      @id @default(autoincrement())\n  purchaseOrderId  Int      @map(\"purchase_order_id\")\n  productId        Int?     @map(\"product_id\")\n  productName      String   @map(\"product_name\") @db.VarChar(255)\n  productSku       String?  @map(\"product_sku\") @db.VarChar(100)\n  variantId        Int?     @map(\"variant_id\")\n  variantInfo      String?  @map(\"variant_info\") @db.VarChar(255)\n  quantityOrdered  Int      @map(\"quantity_ordered\")\n  quantityReceived Int      @default(0) @map(\"quantity_received\")\n  unitCost         Decimal  @map(\"unit_cost\") @db.Decimal(12, 2)\n  totalCost        Decimal  @map(\"total_cost\") @db.Decimal(14, 2)\n  notes            String?  @db.Text\n  createdAt        DateTime @default(now()) @map(\"created_at\")\n\n  purchaseOrder PurchaseOrder @relation(fields: [purchaseOrderId], references: [id], onDelete: Cascade)\n  product       Product?      @relation(fields: [productId], references: [id], onDelete: SetNull)\n\n  @@index([purchaseOrderId])\n  @@map(\"purchase_order_items\")\n}\n\nmodel SupplierPayment {\n  id              Int                   @id @default(autoincrement())\n  storeId         Int                   @map(\"store_id\")\n  supplierId      Int                   @map(\"supplier_id\")\n  purchaseOrderId Int?                  @map(\"purchase_order_id\")\n  paymentNumber   String                @unique @map(\"payment_number\") @db.VarChar(50)\n  amount          Decimal               @db.Decimal(14, 2)\n  paymentDate     DateTime              @map(\"payment_date\") @db.Date\n  paymentMethod   SupplierPaymentMethod @default(BANK_TRANSFER) @map(\"payment_method\")\n  referenceNumber String?               @map(\"reference_number\") @db.VarChar(100)\n  notes           String?               @db.Text\n  createdById     Int?                  @map(\"created_by\")\n  createdAt       DateTime              @default(now()) @map(\"created_at\")\n\n  store         Store          @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  supplier      Supplier       @relation(fields: [supplierId], references: [id], onDelete: Restrict)\n  purchaseOrder PurchaseOrder? @relation(fields: [purchaseOrderId], references: [id], onDelete: SetNull)\n  createdBy     User?          @relation(fields: [createdById], references: [id], onDelete: SetNull)\n\n  @@index([supplierId])\n  @@index([paymentDate])\n  @@map(\"supplier_payments\")\n}\n\n// ---------------------------------------------------------------------------\n// Accounting\n// ---------------------------------------------------------------------------\n\nenum AccountType {\n  ASSET\n  LIABILITY\n  EQUITY\n  REVENUE\n  EXPENSE\n  COGS\n}\n\nenum NormalBalance {\n  DEBIT\n  CREDIT\n}\n\nenum JournalReferenceType {\n  MANUAL\n  ORDER\n  EXPENSE\n  PURCHASE\n  RETURN\n  PAYMENT\n  ADJUSTMENT\n}\n\nenum JournalStatus {\n  DRAFT\n  POSTED\n  REVERSED\n}\n\nmodel Account {\n  id             Int           @id @default(autoincrement())\n  storeId        Int           @map(\"store_id\")\n  code           String        @map(\"account_code\") @db.VarChar(20)\n  name           String        @map(\"account_name\") @db.VarChar(255)\n  type           AccountType   @map(\"account_type\")\n  parentId       Int?          @map(\"parent_id\")\n  description    String?       @db.Text\n  isSystem       Boolean       @default(false) @map(\"is_system\")\n  isActive       Boolean       @default(true) @map(\"is_active\")\n  normalBalance  NormalBalance @map(\"normal_balance\")\n  currentBalance Decimal       @default(0) @map(\"current_balance\") @db.Decimal(14, 2)\n  createdAt      DateTime      @default(now()) @map(\"created_at\")\n  updatedAt      DateTime      @updatedAt @map(\"updated_at\")\n\n  store    Store              @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  parent   Account?           @relation(\"AccountTree\", fields: [parentId], references: [id], onDelete: SetNull)\n  children Account[]          @relation(\"AccountTree\")\n  lines    JournalEntryLine[]\n\n  @@unique([storeId, code])\n  @@index([type])\n  @@map(\"chart_of_accounts\")\n}\n\nmodel JournalEntry {\n  id            Int                  @id @default(autoincrement())\n  storeId       Int                  @map(\"store_id\")\n  entryNumber   String               @unique @map(\"entry_number\") @db.VarChar(50)\n  entryDate     DateTime             @map(\"entry_date\") @db.Date\n  description   String               @db.Text\n  referenceType JournalReferenceType @default(MANUAL) @map(\"reference_type\")\n  referenceId   Int?                 @map(\"reference_id\")\n  totalDebit    Decimal              @map(\"total_debit\") @db.Decimal(14, 2)\n  totalCredit   Decimal              @map(\"total_credit\") @db.Decimal(14, 2)\n  status        JournalStatus        @default(DRAFT)\n  postedAt      DateTime?            @map(\"posted_at\")\n  postedById    Int?                 @map(\"posted_by\")\n  reversedById  Int?                 @map(\"reversed_by_id\")\n  notes         String?              @db.Text\n  createdById   Int?                 @map(\"created_by\")\n  createdAt     DateTime             @default(now()) @map(\"created_at\")\n  updatedAt     DateTime             @updatedAt @map(\"updated_at\")\n\n  store      Store              @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  createdBy  User?              @relation(\"JournalCreator\", fields: [createdById], references: [id], onDelete: SetNull)\n  postedBy   User?              @relation(\"JournalPoster\", fields: [postedById], references: [id], onDelete: SetNull)\n  reversedBy JournalEntry?      @relation(\"JournalReversal\", fields: [reversedById], references: [id], onDelete: SetNull)\n  reverses   JournalEntry[]     @relation(\"JournalReversal\")\n  lines      JournalEntryLine[]\n\n  @@index([storeId, entryDate])\n  @@index([referenceType, referenceId])\n  @@index([status])\n  @@map(\"journal_entries\")\n}\n\nmodel JournalEntryLine {\n  id             Int      @id @default(autoincrement())\n  journalEntryId Int      @map(\"journal_entry_id\")\n  accountId      Int      @map(\"account_id\")\n  description    String?  @db.VarChar(255)\n  debitAmount    Decimal  @default(0) @map(\"debit_amount\") @db.Decimal(14, 2)\n  creditAmount   Decimal  @default(0) @map(\"credit_amount\") @db.Decimal(14, 2)\n  createdAt      DateTime @default(now()) @map(\"created_at\")\n\n  journalEntry JournalEntry @relation(fields: [journalEntryId], references: [id], onDelete: Cascade)\n  account      Account      @relation(fields: [accountId], references: [id], onDelete: Restrict)\n\n  @@index([journalEntryId])\n  @@index([accountId])\n  @@map(\"journal_entry_lines\")\n}\n\n// ---------------------------------------------------------------------------\n// Campaigns / Meta integration\n// ---------------------------------------------------------------------------\n\nenum CampaignPlatform {\n  ALL\n  FACEBOOK\n  INSTAGRAM\n  WHATSAPP\n  TELEGRAM\n  TWITTER\n}\n\nenum CampaignMessageType {\n  PROMOTION\n  ANNOUNCEMENT\n  GREETING\n  OFFER\n  EVENT\n  CUSTOM\n}\n\nenum CampaignEventType {\n  VIEW\n  COPY\n  CLICK\n  SHARE\n  ENGAGEMENT\n}\n\nenum CampaignGoalType {\n  VIEWS\n  COPIES\n  CLICKS\n  SHARES\n  ENGAGEMENTS\n}\n\nenum CampaignNoteType {\n  GENERAL\n  PERFORMANCE\n  ISSUE\n  IDEA\n}\n\nmodel Campaign {\n  id               Int                 @id @default(autoincrement())\n  storeId          Int                 @map(\"store_id\")\n  title            String              @db.VarChar(255)\n  platform         CampaignPlatform    @default(ALL)\n  messageType      CampaignMessageType @default(PROMOTION) @map(\"message_type\")\n  content          String              @db.Text\n  shortContent     String?             @map(\"short_content\") @db.VarChar(500)\n  hashtags         String?             @db.VarChar(500)\n  callToAction     String?             @map(\"call_to_action\") @db.VarChar(255)\n  ctaUrl           String?             @map(\"cta_url\") @db.VarChar(500)\n  imagePath        String?             @map(\"image_path\") @db.VarChar(255)\n  scheduledAt      DateTime?           @map(\"scheduled_at\")\n  expiresAt        DateTime?           @map(\"expires_at\")\n  isActive         Boolean             @default(true) @map(\"is_active\")\n  isPinned         Boolean             @default(false) @map(\"is_pinned\")\n  copyCount        Int                 @default(0) @map(\"copy_count\")\n  totalViews       Int                 @default(0) @map(\"total_views\")\n  totalClicks      Int                 @default(0) @map(\"total_clicks\")\n  totalShares      Int                 @default(0) @map(\"total_shares\")\n  totalEngagements Int                 @default(0) @map(\"total_engagements\")\n  conversionRate   Decimal             @default(0) @map(\"conversion_rate\") @db.Decimal(5, 2)\n  lastActivityAt   DateTime?           @map(\"last_activity_at\")\n  createdById      Int?                @map(\"created_by\")\n  createdAt        DateTime            @default(now()) @map(\"created_at\")\n  updatedAt        DateTime            @updatedAt @map(\"updated_at\")\n\n  store      Store               @relation(fields: [storeId], references: [id], onDelete: Cascade)\n  createdBy  User?               @relation(fields: [createdById], references: [id], onDelete: SetNull)\n  events     CampaignEvent[]\n  dailyStats CampaignDailyStat[]\n  goals      CampaignGoal[]\n  notes      CampaignNote[]\n\n  @@index([storeId, isActive])\n  @@index([platform, isActive])\n  @@map(\"campaign_messages\")\n}\n\nmodel CampaignEvent {\n  id         Int               @id @default(autoincrement())\n  campaignId Int               @map(\"campaign_id\")\n  type       CampaignEventType @map(\"event_type\")\n  platform   String?           @db.VarChar(50)\n  source     String?           @db.VarChar(100)\n  ipAddress  String?           @map(\"ip_address\") @db.VarChar(45)\n  userAgent  String?           @map(\"user_agent\") @db.VarChar(500)\n  referrer   String?           @db.VarChar(500)\n  metadata   Json?\n  createdAt  DateTime          @default(now()) @map(\"created_at\")\n\n  campaign Campaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n\n  @@index([campaignId, type])\n  @@index([createdAt])\n  @@map(\"campaign_analytics\")\n}\n\nmodel CampaignDailyStat {\n  id          Int      @id @default(autoincrement())\n  campaignId  Int      @map(\"campaign_id\")\n  date        DateTime @map(\"stat_date\") @db.Date\n  views       Int      @default(0)\n  copies      Int      @default(0)\n  clicks      Int      @default(0)\n  shares      Int      @default(0)\n  engagements Int      @default(0)\n  uniqueViews Int      @default(0) @map(\"unique_views\")\n  createdAt   DateTime @default(now()) @map(\"created_at\")\n  updatedAt   DateTime @updatedAt @map(\"updated_at\")\n\n  campaign Campaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n\n  @@unique([campaignId, date])\n  @@index([date])\n  @@map(\"campaign_daily_stats\")\n}\n\nmodel CampaignGoal {\n  id           Int              @id @default(autoincrement())\n  campaignId   Int              @map(\"campaign_id\")\n  type         CampaignGoalType @map(\"goal_type\")\n  targetValue  Int              @map(\"target_value\")\n  currentValue Int              @default(0) @map(\"current_value\")\n  startDate    DateTime?        @map(\"start_date\") @db.Date\n  endDate      DateTime?        @map(\"end_date\") @db.Date\n  isAchieved   Boolean          @default(false) @map(\"is_achieved\")\n  achievedAt   DateTime?        @map(\"achieved_at\")\n  createdAt    DateTime         @default(now()) @map(\"created_at\")\n\n  campaign Campaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n\n  @@index([campaignId])\n  @@map(\"campaign_goals\")\n}\n\nmodel CampaignNote {\n  id         Int              @id @default(autoincrement())\n  campaignId Int              @map(\"campaign_id\")\n  userId     Int?             @map(\"user_id\")\n  note       String           @db.Text\n  type       CampaignNoteType @default(GENERAL) @map(\"note_type\")\n  createdAt  DateTime         @default(now()) @map(\"created_at\")\n\n  campaign Campaign @relation(fields: [campaignId], references: [id], onDelete: Cascade)\n  user     User?    @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  @@index([campaignId])\n  @@map(\"campaign_notes\")\n}\n\nenum MetaPlatform {\n  FACEBOOK\n  INSTAGRAM\n  WHATSAPP\n}\n\nenum MetaMessageType {\n  TEXT\n  IMAGE\n  VIDEO\n  AUDIO\n  FILE\n  STICKER\n  TEMPLATE\n  INTERACTIVE\n}\n\nenum MetaMessageStatus {\n  SENT\n  DELIVERED\n  READ\n  FAILED\n}\n\nenum MetaInsightPeriod {\n  DAY\n  WEEK\n  MONTH\n  LIFETIME\n}\n\nenum MetaTemplateCategory {\n  MARKETING\n  UTILITY\n  AUTHENTICATION\n}\n\nenum MetaTemplateStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nmodel MetaIntegration {\n  id                 Int          @id @default(autoincrement())\n  storeId            Int          @map(\"store_id\")\n  platform           MetaPlatform\n  pageId             String?      @map(\"page_id\") @db.VarChar(100)\n  pageName           String?      @map(\"page_name\") @db.VarChar(255)\n  pageAccessToken    String?      @map(\"page_access_token\") @db.Text\n  userAccessToken    String?      @map(\"user_access_token\") @db.Text\n  tokenExpiresAt     DateTime?    @map(\"token_expires_at\")\n  phoneNumberId      String?      @map(\"phone_number_id\") @db.VarChar(100)\n  whatsappBusinessId String?      @map(\"whatsapp_business_id\") @db.VarChar(100)\n  isActive           Boolean      @default(true) @map(\"is_active\")\n  lastSyncAt         DateTime?    @map(\"last_sync_at\")\n  settings           Json?\n  createdAt          DateTime     @default(now()) @map(\"created_at\")\n  updatedAt          DateTime     @updatedAt @map(\"updated_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@unique([storeId, platform])\n  @@map(\"meta_integrations\")\n}\n\nmodel MetaMessage {\n  id               Int               @id @default(autoincrement())\n  storeId          Int               @map(\"store_id\")\n  platform         MetaPlatform\n  externalId       String            @unique @map(\"message_id\") @db.VarChar(255)\n  conversationId   String?           @map(\"conversation_id\") @db.VarChar(255)\n  senderId         String?           @map(\"sender_id\") @db.VarChar(100)\n  senderName       String?           @map(\"sender_name\") @db.VarChar(255)\n  senderProfilePic String?           @map(\"sender_profile_pic\") @db.VarChar(500)\n  recipientId      String?           @map(\"recipient_id\") @db.VarChar(100)\n  type             MetaMessageType   @default(TEXT) @map(\"message_type\")\n  content          String?           @db.Text\n  mediaUrl         String?           @map(\"media_url\") @db.VarChar(500)\n  isIncoming       Boolean           @default(true) @map(\"is_incoming\")\n  isRead           Boolean           @default(false) @map(\"is_read\")\n  status           MetaMessageStatus @default(SENT)\n  metadata         Json?\n  createdAt        DateTime          @default(now()) @map(\"created_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@index([conversationId])\n  @@index([senderId])\n  @@index([createdAt])\n  @@map(\"meta_messages\")\n}\n\nmodel MetaPageInsight {\n  id          Int               @id @default(autoincrement())\n  storeId     Int               @map(\"store_id\")\n  platform    MetaPlatform\n  pageId      String            @map(\"page_id\") @db.VarChar(100)\n  metricName  String            @map(\"metric_name\") @db.VarChar(100)\n  metricValue Decimal?          @map(\"metric_value\") @db.Decimal(14, 2)\n  period      MetaInsightPeriod @default(DAY)\n  date        DateTime          @map(\"stat_date\") @db.Date\n  metadata    Json?\n  createdAt   DateTime          @default(now()) @map(\"created_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@unique([storeId, platform, pageId, metricName, date, period])\n  @@index([date])\n  @@map(\"meta_page_insights\")\n}\n\nmodel MetaMessageTemplate {\n  id         Int                  @id @default(autoincrement())\n  storeId    Int                  @map(\"store_id\")\n  templateId String?              @map(\"template_id\") @db.VarChar(100)\n  name       String               @db.VarChar(255)\n  language   String               @default(\"en\") @db.VarChar(10)\n  category   MetaTemplateCategory @default(MARKETING)\n  status     MetaTemplateStatus   @default(PENDING)\n  components Json?\n  createdAt  DateTime             @default(now()) @map(\"created_at\")\n  updatedAt  DateTime             @updatedAt @map(\"updated_at\")\n\n  store Store @relation(fields: [storeId], references: [id], onDelete: Cascade)\n\n  @@index([storeId])\n  @@map(\"meta_message_templates\")\n}\n"
}

